var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 덕분에 늦지 않게 모두 정리한 것 같네요.","JPN":"ハハ、おかげで時間内に処理できたようですね。","ENG":"Hah hah, we've managed to clear the site before it was too late.","TWN":"哈哈，多虧了米娜小姐，我們準時解決了呢。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"역시 미나 양의 잠재력은 대단하다니까요?","JPN":"やっぱり、ミナさんの潜在能力はすごいですね？","ENG":"I knew you had great potential in you.","TWN":"米娜小姐果然潛力無窮呢！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양, 몸은 좀 어때요?","JPN":"ミナさん、体調はどうですか？","ENG":"How are you feeling, Mina?","TWN":"米娜小姐，妳身體還好嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......아파.","JPN":"……だるい。","ENG":"It hurts.","TWN":"……痛。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"온 몸이 두들겨 맞은 것 같아......","JPN":"全身打撲のような感覚だよ……","ENG":"I feel like my whole body was beaten to a pulp.","TWN":"好像全身都被揍了一頓……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"대체 나한테 무슨 짓을 한 거야?","JPN":"いったい私に何をしたの？","ENG":"What did you do to me?","TWN":"你到底對我做了什麼？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"검을 깨웠다는 건 또 무슨 소리고?","JPN":"剣を呼び起こしたって、どういう意味？","ENG":"And what does it mean to awaken the sword?","TWN":"什麼叫作劍被喚醒了？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양이 가진 클리포트 인자는 말하자면 푹 젖은 화약 같은 거라서요.","JPN":"ミナさんが持つクリフォト・ファクターは、言ってしまえば、ずぶ濡れの火薬のようなものなんです。","ENG":"To put it simply, the Qliphoth Factor in your body is like a batch of gunpowder drenched in water.","TWN":"米娜小姐擁有的逆卡巴拉因子就像濕透了的火藥一樣。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"순도는 말도 안되게 높지만...... 활성화가 어려워요.","JPN":"純度はあり得ないほど高いですが……活性化が難しいので、","ENG":"It's ridiculously high in purity, but it's extremely difficult to activate.","TWN":"雖然純度極高……但要使它活性化卻很難。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그래서 자극을 줘서 격발시킬 뇌관이 필요한 거죠.","JPN":"刺激を与えて撃発させるような雷管が必要です。","ENG":"That's why you needed a stimulus, or a detonator, to make it work.","TWN":"所以需要給予它刺激，使它引爆雷管。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이 검이...... 그 뇌관이라고?","JPN":"この剣が……その雷管なの？","ENG":"And this sword was the stimulus, you're saying?","TWN":"這把劍……就是雷管嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"가능성은 높다고 생각했죠.","JPN":"可能性は高いと思いました。","ENG":"I thought it was highly probable, at least.","TWN":"我認為可能性很高。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"일반적으로 이런 <color=#ffd34c>마검</color> 계열의 무기는 사용자로부터 필요한 힘을 강제 추출하는 기능을 가지고 있으니까요.","JPN":"普通、こういう<color=#ffd34c>魔剣</color>の類は、\\n必要な力を持ち主から強制的に抽出する機能を持っていますからね。","ENG":"An <color=#ffd34c>evil sword</color> like this normally operates based on the energy it juices out from its owner.","TWN":"因為一般來說，這種<color=#ffd34c>魔劍</color>系列的武器，都會從使用者身上強制抽出它所需要的力量。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그 정도가 지나치면 모든 힘을 빨아 먹히고 껍데기만 남을 수도 있겠지만......","JPN":"度が過ぎると、すべての力を吸い取られて、生ける屍みたいになるかもしれませんが……","ENG":"The sword would suck its owner dry if whoever owns it were weak...","TWN":"如果超過一定限度，有可能會被吸食掉所有力量，只剩下一個空殼……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양의 잠재력을 생각한다면...... 그냥 좀 불편한 정도일 겁니다.","JPN":"ミナさんの潜在能力を考慮すると……少し違和感がある程度だと思います。","ENG":"But considering the power latent within you, it'd cause no more than slight uneasiness,","TWN":"但考慮到米娜小姐的潛力……這只是稍微有點不便而已吧。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그것도 차차 가라앉겠죠.","JPN":"それも次第に落ち着くでしょうね。","ENG":"which will soon go away as time passes.","TWN":"而且，痛覺也會逐漸緩解的。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼...... 그 클리포트인가 뭔가 하는 힘을 사용할 수 있는 거야?","JPN":"じゃあ……そのクリフォトなんとかとやらを使えるようになるの？","ENG":"Then... Can I now use the power of Qliphoth whatever?","TWN":"所以……這個逆卡巴拉因子可以用來做什麼呢？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그건 미나 양의 노력에 달렸죠.","JPN":"それはミナさんの努力次第ですね。","ENG":"That depends on your efforts, Mina.","TWN":"那就端看米娜小姐的努力了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};